module thresholding (
    input [7:0] pixel_value,
    output reg obf_binary_output
);
    // Define the threshold value
    parameter THRESHOLD = 128;

    always @(*) begin
        if (pixel_value >= THRESHOLD) 
            obf_binary_output = 1'b1; // Above threshold
        else 
            obf_binary_output = 1'b0; // Below threshold
    end
endmodule
